diagram.mermaid:
flowchart LR
  A{official purse from ESPN?} -->|yes| B[show purse, project earnings]
  A -->|no| C{estimatedPurse set by admin?}
  C -->|yes| D["show ~estimate, project earnings"]
  C -->|no| E[hide purse, skip projections]
  classDef added fill:#d3f9d8,stroke:#37b24d,color:#1b1b1b;
  class D added;

d2:
direction: right
"Admin": { class: actor }
"ESPN API": { class: external }
"admin.updateTournament": { class: changed }
"adminService + adminRepo": { class: changed }
"sync service": { class: changed }
"tournament table": { class: store }
"formatPurse": { class: added }
"user pages": { class: changed }
"Admin" -> "admin.updateTournament": sets estimate
"admin.updateTournament" -> "adminService + adminRepo"
"adminService + adminRepo" -> "tournament table": estimated_purse
"ESPN API" -> "sync service": official purse
"sync service" -> "tournament table": writes purse
"tournament table" -> "sync service": estimatedPurse fallback
"tournament table" -> "user pages": purse + estimatedPurse
"user pages" -> "formatPurse": "~ prefix display"

mermaid:
flowchart LR
  Admin[Admin] -->|sets estimate| RT[admin.updateTournament]
  RT --> SVC[adminService + adminRepo]
  SVC -->|estimated_purse| DB[(tournament table)]
  ESPN[ESPN API] -->|official purse| SYNC[sync service]
  SYNC -->|writes purse| DB
  DB -->|estimatedPurse fallback| SYNC
  DB -->|purse + estimatedPurse| PAGES[user pages]
  PAGES -->|"~ prefix display"| FMT[formatPurse]
  classDef changed fill:#ffd43b,stroke:#f08c00,color:#1b1b1b,stroke-width:2px;
  classDef added fill:#d3f9d8,stroke:#37b24d,color:#1b1b1b;
  classDef actor fill:#d0ebff,stroke:#4dabf7,color:#1b1b1b;
  classDef external fill:#f1f3f5,stroke:#adb5bd,color:#1b1b1b;
  classDef store fill:#e5dbff,stroke:#9775fa,color:#1b1b1b;
  class RT,SVC,SYNC,PAGES changed;
  class FMT added;
  class Admin actor;
  class ESPN external;
  class DB store;

diagram.d2:
shape: sequence_diagram
cron: { class: actor }
sync: { class: changed }
ESPN: { class: external }
db: { class: store }
cron -> sync: syncLiveStandings(id)
sync -> db: findTournamentForSync — purse, estimatedPurse
sync -> ESPN: getResults(espnId)
ESPN -> sync: live leaderboard
sync -> ESPN: getEventDetails(espnId) for purse
ESPN -> sync: fails — purse not published
sync -> sync: effectivePurse = purse ?? estimatedPurse
sync -> db: upsert projected earnings from calculateEarnings
